Chat Edit: '```powershell
# 🔥 RawrXD IDE Audit Fix — Ultra-Condensed PowerShell Wire Script
# Fixes: Broken void inheritance, Qt contamination, disconnected SignalSlot, isolated HotPatcher/Security, duplicate registries

# 1. SURGICAL FIX: Repair 5 broken components inheriting from void → RawrXD::Window
Get-ChildItem -Path "D:\rawrxd\src" -Recurse -Include "*.h","*.hpp" | Select-String -Pattern "class\s+(\w+)\s*:\s*public\s+void" | ForEach-Object { $newContent = (Get-Content $_.Path -Raw) -replace "class\s+$($_.Matches.Groups[1].Value)\s*:\s*public\s+void", "class $($_.Matches.Groups[1].Value) : public RawrXD::Window"; Set-Content -Path $_.Path -Value $newContent -NoNewline; Write-Host "🔧 Fixed $($_.Matches.Groups[1].Value) in $($_.Path)" -ForegroundColor Cyan }

# 2. DECONTAMINATION: Purge QTreeWidgetItem and Qt artifacts from "Qt-free" headers
Get-ChildItem -Path "D:\rawrxd\src" -Recurse -Include "*.h","*.hpp","*.cpp" | Where-Object { $_ -notmatch "rawrxd_compiler_qt|IDEMainWindow|\.qt_backup" } | ForEach-Object { $content = Get-Content $_.Path -Raw; if ($content -match "QTreeWidgetItem|QMainWindow|QDockWidget|QTextEdit|#include\s+<Q[ a-zA-Z]+>") { $clean = $content -replace "QTreeWidgetItem\s*\*\s*\w+\s*;?", "// Qt purged" -replace "#include\s+<Q[ a-zA-Z]+>", "// Qt removed" -replace "QMainWindow|QDockWidget|QTextEdit", "RawrXD::Window"; Set-Content -Path $_.Path -Value $clean -NoNewline; Write-Host "🧹 Purged Qt from $($_.Name)" -ForegroundColor Yellow } }

# 3. SIGNAL SLOT WIRING: Inject SignalSlot into components using raw callbacks (GhostTextRenderer pattern)
Get-ChildItem -Path "D:\rawrxd\src" -Include "*.h","*.hpp" -Recurse | Where-Object { $_.Name -notmatch "RawrXD_SignalSlot|GhostTextRenderer" } | ForEach-Object { $content = Get-Content $_.Path -Raw; if ($content -match "std::function|callback|On[A-Z]\w+\s*\(" -and $content -notmatch "RawrXD::Signal") { $includeSig = "#include `"RawrXD_SignalSlot.h`"`n" + $content; $wired = $includeSig -replace "(class\s+\w+\s*:\s*public\s+(?:RawrXD::)?Window)", '$1, public RawrXD::Trackable' -replace "std::function<void\(\)>\s+(\w+)\s*;", 'RawrXD::Signal<> $1;' -replace "std::function<void\(([^)]+)\)>\s+(\w+)\s*;", 'RawrXD::Signal<$1> $2;'; Set-Content -Path $_.Path -Value $wired -NoNewline; Write-Host "📡 Wired SignalSlot into $($_.Name)" -ForegroundColor Green } }

# 4. HOTPATCH BRIDGE: Connect HotPatcher to Win32IDE panels and Agentic systems
$hotpatchBridge = @"
// AUTO-GENERATED HOTPATCH WIRE
#pragma once
#include "hot_patcher.h"
#include "RawrXD_SignalSlot.h"
#include "agent/agentic_hotpatch_orchestrator.hpp"
class HotpatchUIWire : public RawrXD::Trackable {
    HotPatcher* m_hp; RawrXD::Signal<HRESULT, std::string> OnPatchApplied;
public: HotpatchUIWire(HotPatcher* hp) : m_hp(hp) { m_hp->OnPatchComplete.connect(this, &HotpatchUIWire::Forward); }
    void Forward(HRESULT r, const std::string& s) { OnPatchApplied.emit(r,s); }
};
"@; Set-Content -Path "D:\rawrxd\src\hotpatch_ui_wire.hpp" -Value $hotpatchBridge; Write-Host "🔥 Created HotpatchUIWire bridge" -ForegroundColor Red; (Get-Content "D:\rawrxd\src\win32app\Win32IDE.h" -Raw) -replace "(#include\s+`"Win32IDE_AgenticBridge.h`")", "`$1`n#include `"../hotpatch_ui_wire.hpp`"" | Set-Content "D:\rawrxd\src\win32app\Win32IDE.h" -NoNewline

# 5. SECURITY WIRING: Inject RBAC into GlobalContext and AgenticCore
$securityWire = @"
// AUTO-GENERATED SECURITY WIRE
#pragma once
#include "auth/rbac_engine.hpp"
#include "shared_context.h"
class SecurityContextInjector {
public: static void Inject() { 
    GlobalContext::Instance().RegisterSecurity(RBACEngine::Instance());
    RBACEngine::Instance().EnableHotpatchGuard(true);
}}
"@; Set-Content -Path "D:\rawrxd\src\security_wire.hpp" -Value $securityWire; Write-Host "🔒 Injected RBAC wiring" -ForegroundColor Magenta; Get-ChildItem "D:\rawrxd\src" -Include "agentic_core.cpp","agentic_executor.h","agentic_ide.h" -Recurse | ForEach-Object { (Get-Content $_.Path -Raw) -replace "(#include.*agentic.*)", "`$1`n#include `"security_wire.hpp`"" | Set-Content $_.Path -NoNewline }

# 6. REGISTRY MERGE: Consolidate duplicate ToolRegistries into unified system
$unifiedRegistry = @"
// AUTO-GENERATED UNIFIED TOOL REGISTRY
#pragma once
#include "tool_registry.h"
#include "agentic/ToolRegistry.h"
#define TOOL_REGISTRY UnifiedToolRegistry::Instance()
class UnifiedToolRegistry : public ToolRegistry, public agentic::ToolRegistry {
    static UnifiedToolRegistry* inst; UnifiedToolRegistry() {}
public: static UnifiedToolRegistry* Instance() { if(!inst) inst=new UnifiedToolRegistry(); return inst; }
    void RegisterBoth(const std::string& n, auto cb) { ToolRegistry::Register(n,cb); agentic::ToolRegistry::Register(n,cb); }
};
"@; Set-Content -Path "D:\rawrxd\src\unified_tool_registry.hpp" -Value $unifiedRegistry; Get-ChildItem "D:\rawrxd\src" -Include "*.cpp","*.h" -Recurse | ForEach-Object { (Get-Content $_.Path -Raw) -replace '#include\s+"agentic/RawrXD_ToolRegistry.h"', '#include "unified_tool_registry.hpp"' -replace '#include\s+"tool_registry.h"(?!.*agentic)', '#include "unified_tool_registry.hpp"' | Set-Content $_.Path -NoNewline }; Write-Host "🔧 Merged ToolRegistries" -ForegroundColor Blue

# 7. IDEOrchestrator COMPLETION: Add missing subsystems (HotPatcher, Security, ToolRegistry, GUI panes)
$orchestratorPatch = @"
// PATCH BLOCK for ide_orchestrator.h
#include "hot_patcher.h"
#include "auth/rbac_engine.hpp" 
#include "unified_tool_registry.hpp"
#include "security_wire.hpp"
#include "hotpatch_ui_wire.hpp"
// In IDEOrchestrator ctor: SecurityContextInjector::Inject(); m_hotpatch = GlobalContext::Instance().GetHotPatcher();
"@; Add-Content -Path "D:\rawrxd\src\ide_orchestrator.h" -Value $orchestratorPatch; Write-Host "🎯 Patched IDEOrchestrator with missing subsystems" -ForegroundColor Cyan

# 8. COMPILER BRIDGE: Wire ToolchainBridge to AgenticExecutor
Get-Content "D:\rawrxd\src\agentic_executor.h" -Raw | ForEach-Object { $_ -replace "compileProject\(\) \{(?!.*ToolchainBridge)", "compileProject() { ToolchainBridge bridge; return bridge.Compile(m_projectPath); }" } | Set-Content "D:\rawrxd\src\agentic_executor.h" -NoNewline; Write-Host "🔗 Wired ToolchainBridge to AgenticExecutor" -ForegroundColor Green

# 9. DELETE Qt contamination files (backup first)
Move-Item -Path "D:\rawrxd\src\compiler\rawrxd_compiler_qt.cpp" -Destination "D:\rawrxd\src\compiler\rawrxd_compiler_qt.cpp.qt_backup" -Force; Move-Item -Path "D:\rawrxd\src\compiler\rawrxd_compiler_qt.hpp" -Destination "D:\rawrxd\src\compiler\rawrxd_compiler_qt.hpp.qt_backup" -Force; Write-Host "🗑️  Quarantined Qt compiler files" -ForegroundColor Red

# 10. FINAL WIRE: Connect LSPClient to MultiTabEditor (resolve forward declaration)
Get-Content "D:\rawrxd\src\multi_tab_editor.h" -Raw | ForEach-Object { $_ -replace "class LSPClient;.*", "#include `"lsp_client.h`"`nclass LSPClient;" -replace "(class\s+MultiTabEditor\s*:\s*public\s+\w+)", '$1, public LSPClientListener' } | Set-Content "D:\rawrxd\src\multi_tab_editor.h" -NoNewline; Write-Host "🩺 Wired LSP to MultiTabEditor" -ForegroundColor White

Write-Host "`n✅ RAWRXD AUDIT WIRING COMPLETE" -ForegroundColor Green -BackgroundColor Black; Write-Host "Next: Rebuild with: cmake --build build_prod --config Release --target RawrXD-AgenticIDE" -ForegroundColor Yellow
```'
